
-- 1. Create agent_table_schema table
CREATE TABLE public.agent_table_schema (
  table_name text PRIMARY KEY,
  module text NOT NULL DEFAULT 'sales',
  description_en text NOT NULL DEFAULT '',
  description_ar text NOT NULL DEFAULT '',
  columns_doc jsonb NOT NULL DEFAULT '[]'::jsonb,
  relationships jsonb NOT NULL DEFAULT '[]'::jsonb,
  read_hints jsonb NOT NULL DEFAULT '[]'::jsonb,
  updated_at timestamptz NOT NULL DEFAULT now()
);

ALTER TABLE public.agent_table_schema ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Authenticated users can view agent_table_schema"
  ON public.agent_table_schema FOR SELECT TO authenticated
  USING (true);

CREATE POLICY "Admins can manage agent_table_schema"
  ON public.agent_table_schema FOR ALL TO authenticated
  USING (has_role(auth.uid(), 'admin'::app_role))
  WITH CHECK (has_role(auth.uid(), 'admin'::app_role));

