-- 3. Update check constraint to allow 'archived'
ALTER TABLE public.agent_actions DROP CONSTRAINT agent_actions_status_check;
ALTER TABLE public.agent_actions ADD CONSTRAINT agent_actions_status_check CHECK (status = ANY (ARRAY['active','coming_soon','disabled','archived']));

-- 4. Archive all existing agent_actions
UPDATE public.agent_actions SET status = 'archived';

-- 5. Allow admins to manage agent_actions
CREATE POLICY "Admins can manage agent_actions"
  ON public.agent_actions FOR ALL TO authenticated
  USING (has_role(auth.uid(), 'admin'::app_role))
  WITH CHECK (has_role(auth.uid(), 'admin'::app_role));

